.darma-loader-darma-custom-622 {color: var(--loader-color, #7c3aed);
  --loader-secondary-color: #c084fc;
  --loader-bg: #ffffff;
   width: 68px;
   aspect-ratio: 1;
   border: 8px solid currentColor;
   box-sizing: border-box;
   background: radial-gradient(farthest-side,currentColor 98%,#0000) top, radial-gradient(farthest-side,currentColor 98%,#0000) top, radial-gradient(farthest-side,currentColor 98%,#0000) left, radial-gradient(farthest-side,currentColor 98%,#0000) right, radial-gradient(farthest-side,currentColor 98%,#0000) bottom, currentColor;
   background-size: 20px 20px;
   background-repeat: no-repeat;
   filter: blur(4px) contrast(10);
   animation: darma-loader-darma-custom-622-l19 2s infinite;
}
@keyframes darma-loader-darma-custom-622-l19  {
  0% {background-position:top,top,left,right,bottom}
25% {background-position:right,top,left,right,bottom}
50% {background-position:bottom,top,left,right,bottom}
75% {background-position:left,top,left,right,bottom}
100% {background-position:top,top,left,right,bottom}
}

